mapper.select:
SELECT tjca.* , sf.file_id as logoId , case when tair.signature is not null then 'Y' when taiw.signature is not null then 'N' else 'C' end as approvalStatus FROM esg.tb_job_competency_assessment tjca LEFT JOIN esg.tb_orgn_info toi ON toi.orgn_id = tjca.orgn_id AND toi.comp_id = tjca.comp_id LEFT JOIN esg.tb_approval_info taiw ON taiw.target_type = 'JCA' AND taiw.target_id = tjca.write_year || tjca.doc_no AND taiw.param = 'writer' LEFT JOIN esg.tb_approval_info tair ON tair.target_type = 'JCA' AND tair.target_id = tjca.write_year || tjca.doc_no AND tair.param = 'reviewer' LEFT JOIN esg.tb_sys_file sf ON sf.target_id = tjca.hr_id AND sf.target_type = 'hrImg' WHERE tjca.comp_id = #{compId} AND tjca.write_year = #{writeYear}
AND tjca.doc_type = #{docType} AND tjca.doc_no = #{docNo}
ORDER BY tjca.use_yn DESC, tjca.doc_no asc

  SELECT *
    FROM esg.tb_job_competency_assessment_detail
   WHERE comp_id = #{compId}
     AND write_year = #{writeYear}
     AND doc_type = #{docType}
     AND doc_no = #{docNo}
ORDER BY use_yn DESC

