UPDATE esg.tb_job_competency_assessment
SET
    hr_id = #{hrId},
    hr_nm = #{hrNm},
    orgn_id = #{orgnId},
    orgn_nm = #{orgnNm},
    jbrp_id = #{jbrpId},
    jbrp_nm = #{jbrpNm},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND comp_id = #{compId}

UPDATE esg.tb_job_competency_assessment
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND comp_id = #{compId}

UPDATE esg.tb_job_competency_assessment_detail
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND doc_seq = #{docSeq}
  AND comp_id = #{compId}
